import React from 'react';
import './ItemListContainer.css';

const ItemListContainer = ({ greeting }) => {
  return (
    <div className="item-list-container">
      <h2>{greeting}</h2>
      <div className="item-list">
        <div className="item">
          <h3>Simulador de Vuelo</h3>
          <p>Un simulador de vuelo realista para pilotos en entrenamiento.</p>
        </div>
        <div className="item">
          <h3>Simulador de Carreras</h3>
          <p>Experimenta la emoción de las carreras con este simulador.</p>
        </div>
        <div className="item">
          <h3>Simulador de Espacio</h3>
          <p>Explora el espacio y más allá con este simulador.</p>
        </div>
      </div>
    </div>
  );
};

export default ItemListContainer;
